const item = $('Loop Interessados').item.json;

const body = {
  messaging_product: "whatsapp",
  to: String(item.telefone),
  type: "template",
  template: {
    name: "novo_anncio_do_produto_que_voc_procura",
    language: { code: "pt_BR" },
    components: [
      { type: "body", parameters: [ { type: "text", text: String(item.produto_nome || 'seu produto') } ] }
    ]
  }
};

return [{
  json: {
    resultado: body,
    telefone: item.telefone,
    whatsapp_number_id: "1123205217553260",
    anuncio_id: item.anuncio_id,
    candidato_id: item.candidato_id,
    score: item.score
  }
}];

